static const int dy[4] = {0,0,1,-1};

int main(){
    int n;
    if(scanf("%d", &n) != 1) return 0;
    for(int i = 0; i < n; i++){
        for(int j = 0, v; j < n; j++){
            scanf("%d", &v);
            parity[i][j] = (unsigned char)(v & 1);
        }
    }
    if(n == 1){
        printf("0\n");
        return 0;
    }

    // BFS initialization
    int head = 0, tail = 0;
    visited[0][0][0] = true;
    qx[tail] = 0; qy[tail] = 0; qm[tail] = 0;
    tail++;

    int steps = 0;
    while(head < tail){
        int layerEnd = tail;
        for(; head < layerEnd; head++){
            int x = qx[head], y = qy[head];
            int m = qm[head];
            // next mod‐3
            int nm = m == 2 ? 0 : m + 1;
            int rule = nm;
            unsigned char currP = parity[x][y];
            for(int d = 0; d < 4; d++){
                int nx = x + dx[d], ny = y + dy[d];
                if((unsigned)nx >= (unsigned)n || (unsigned)ny >= (unsigned)n) continue;
                unsigned char nextP = parity[nx][ny];
                if(!ok[rule][currP][nextP]) continue;
                if(visited[nx][ny][nm]) continue;
                if(nx == n-1 && ny == n-1){
                    printf("%d\n", steps + 1);
                    return 0;
                }
                visited[nx][ny][nm] = true;
                qx[tail] = nx; qy[tail] = ny; qm[tail] = (unsigned char)nm;
                tail++;
            }
        }
        steps++;
    }

    // unreachable
    printf("-1\n");
    return 0;
}
