/* 
  Algorithm: BFS on augmented state (i, j, step_mod)
  Optimized for cache locality and fast I/O.
*/
#include <cstdio>
#include <cstdint>
#include <cstring>

static const int MAXN = 1000;
static const int MAXS = MAXN * MAXN * 3;

// parity grid: 0=even,1=odd
static uint8_t parity[MAXN][MAXN];
// visited bitmask per cell: bit k set => visited with step_mod=k
static uint8_t visited2[MAXN][MAXN];

// BFS queue arrays
static uint16_t qx[MAXS], qy[MAXS];
static uint8_t  qm[MAXS];

// 4-direction offsets
static const int dx[4] = {1,-1,0,0};
static const int dy[4] = {0,0,1,-1};

// Fast integer reader
static inline int readInt() {
    int x = 0, c = getchar_unlocked();
    while (c < '0' || c > '9') {
        if (c == EOF) return -1;
        c = getchar_unlocked();
    }
    for (; c >= '0' && c <= '9'; c = getchar_unlocked())
        x = x * 10 + (c & 15);
    return x;
}

int main(){
    int n = readInt();
    if (n <= 0) return 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            int v = readInt();
            parity[i][j] = (uint8_t)(v & 1);
        }
    }
    if (n == 1) {
        // Already at target
        puts("0");
        return 0;
    }

    // Clear visited bitmask array
    memset(visited2, 0, sizeof(visited2));

    // BFS init
    int head = 0, tail = 0;
    visited2[0][0] = 1 << 0;  // visited mod-3=0 at start
    qx[tail] = 0; qy[tail] = 0; qm[tail] = 0;
    tail++;

    int steps = 0;
    while (head < tail) {
        int layerEnd = tail;
        for (; head < layerEnd; head++) {
            int x = qx[head], y = qy[head];
            int m = qm[head];
            // compute next step_mod
            int nm = m + 1;
            if (nm == 3) nm = 0;
            int rule = nm;  // 0=same,1=odd->even,2=even->odd
            uint8_t cp = parity[x][y];
            for (int d = 0; d < 4; d++) {
                int nx = x + dx[d], ny = y + dy[d];
                if ((unsigned)nx >= (unsigned)n || (unsigned)ny >= (unsigned)n)
                    continue;
                uint8_t np = parity[nx][ny];
                // parity rule check
                if (rule == 0) {
                    if (np != cp) continue;
                } else if (rule == 1) {
                    // odd->even
                    if (!(cp == 1 && np == 0)) continue;
                } else {
                    // even->odd
                    if (!(cp == 0 && np == 1)) continue;
                }
                // already visited?
                uint8_t bit = (uint8_t)(1u << nm);
                if (visited2[nx][ny] & bit) continue;
                // reached target?
                if (nx == n-1 && ny == n-1) {
                    // one more step from current
                    printf("%d\n", steps + 1);
                    return 0;
                }
                // mark and enqueue
                visited2[nx][ny] |= bit;
                qx[tail] = (uint16_t)nx;
                qy[tail] = (uint16_t)ny;
                qm[tail] = (uint8_t)nm;
                tail++;
            }
        }
        steps++;
    }

